//-------------------------------------------------------------------------
// 매출취소
//-------------------------------------------------------------------------
scwin.f_masterCancel = async function () {
  var flag = "";
  var row;
  for (row = 0; row < ds_master.getRowCount(); row++) {
    if (ds_master.getCellData(row, "modCls") == "T") {
      flag = "T";
      //ds_master.NameValue(row, "sellYm") = ed_sellYmCreate.Text;
      if (ds_master.getCellData(row, "sellCreatYn") == "0") {
        $c.win.alert($p, "매출이 생성되어 있지 않습니다.");
        ds_master.setRowPosition(row);
        //gr_master.focus();
        return true;
      }
    }
  }
  if ($c.gus.cfIsNull($p, flag)) {
    $c.win.alert($p, "선택된 작업이 없습니다.");
    return;
  }
  var chkAlert = await $c.win.confirm($p, "저장하시겠습니까?");
  if (chkAlert == true) {
    // 저장하시겠습니까?         	 
    $c.sbm.execute($p, sbm_CancelMaster);
  }
};

//-------------------------------------------------------------------------
